/* BTTooltip — hover tooltip balloon.
   Figma: node 479-2624 (Tooltip section, variants Top/Bottom/Left/Right).
   Positioning is computed in JS; this file owns only visual appearance + animation.
   All colours via @btech/tokens CSS vars — no hex fallbacks (CLAUDE.md §6). */

/* ── Trigger wrapper ── */

.bt-tooltip {
  position: relative;
  display: inline-flex;
}

/* ── Floating balloon (placed in document.body via Teleport/portal) ── */

.bt-tooltip__balloon {
  position: fixed;
  z-index: 1060;
  width: 320px;
  max-width: calc(100vw - 32px);
  pointer-events: none;

  /* hidden by default */
  opacity: 0;
  visibility: hidden;
  transition:
    opacity 0.15s ease,
    transform 0.15s ease,
    visibility 0s linear 0.15s;
}

.bt-tooltip__balloon.bt-tooltip__balloon--visible {
  pointer-events: all;
  opacity: 1;
  visibility: visible;
  transition:
    opacity 0.15s ease,
    transform 0.15s ease,
    visibility 0s linear 0s;
}

/* ── Slide-in offset while hidden (tiny nudge toward origin direction) ── */
.bt-tooltip__balloon--top    { transform: translateY(4px); }
.bt-tooltip__balloon--bottom { transform: translateY(-4px); }
.bt-tooltip__balloon--left   { transform: translateX(4px); }
.bt-tooltip__balloon--right  { transform: translateX(-4px); }

.bt-tooltip__balloon--visible.bt-tooltip__balloon--top,
.bt-tooltip__balloon--visible.bt-tooltip__balloon--bottom,
.bt-tooltip__balloon--visible.bt-tooltip__balloon--left,
.bt-tooltip__balloon--visible.bt-tooltip__balloon--right {
  transform: none;
}

/* ── Arrow ── */

/*
  Arrow is a 16×8 (horizontal) or 8×16 (vertical) SVG caret with a
  slightly rounded tip (path "M0 8 L7 1 Q8 0 9 1 L16 8 Z").
  Position is set dynamically via --bt-arrow-offset (px from balloon edge
  to trigger centre), so the arrow always points at the trigger's centre
  even after viewport clamping.
*/

.bt-tooltip__arrow {
  display: block;
  flex-shrink: 0;
}

/* Arrow wrapper — horizontal (top / bottom arrows).
   JS sets --bt-arrow-offset = triggerCenterX − clampedBalloonLeft. */
.bt-tooltip__arrow-row {
  position: relative;
  width: 100%;
  height: 8px;
  flex-shrink: 0;
}

.bt-tooltip__arrow-row .bt-tooltip__arrow {
  position: absolute;
  /* centre of arrow SVG lands on trigger centre */
  left: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* Arrow wrapper — vertical (left / right arrows).
   JS sets --bt-arrow-offset = triggerCenterY − clampedBalloonTop. */
.bt-tooltip__arrow-col {
  position: relative;
  width: 8px;
  flex-shrink: 0;
  align-self: stretch;
}

.bt-tooltip__arrow-col .bt-tooltip__arrow {
  position: absolute;
  /* centre of arrow SVG lands on trigger centre */
  top: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* ── Balloon layout: arrow + body ── */

.bt-tooltip__balloon--top,
.bt-tooltip__balloon--bottom {
  display: flex;
  flex-direction: column;
}
.bt-tooltip__balloon--top    { flex-direction: column-reverse; } /* body on top, arrow below */
.bt-tooltip__balloon--bottom { flex-direction: column; }         /* arrow on top, body below */

.bt-tooltip__balloon--left,
.bt-tooltip__balloon--right {
  display: flex;
  flex-direction: row;
  align-items: stretch; /* stretch so arrow-col fills body height → center works */
  width: auto;
}
.bt-tooltip__balloon--left  { flex-direction: row-reverse; } /* body on left, arrow on right */
.bt-tooltip__balloon--right { flex-direction: row; }          /* arrow on left, body on right */

/* ── Balloon body ── */

.bt-tooltip__body {
  background: var(--bg-inverse);
  border-radius: var(--radius-sm);
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  width: 320px;
  max-width: calc(100vw - 32px);
  box-sizing: border-box;
}

/* For left/right balloons the body width should not be fixed */
.bt-tooltip__balloon--left  .bt-tooltip__body,
.bt-tooltip__balloon--right .bt-tooltip__body {
  width: max-content;
  min-width: 180px;
  max-width: 320px;
}

/* ── Text ── */

.bt-tooltip__text {
  font-family: var(--typography-font-family-sans);
  font-size: 14px;
  font-weight: 500;
  line-height: 16px;
  color: var(--text-inverse);
  margin: 0;
}

/**
 * BTTooltip — hover tooltip wrapping a trigger element.
 *
 * Figma: https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=479-2624
 *
 * @example
 * ```tsx
 * <BTTooltip text="Klik untuk menyimpan" position="top">
 *   <BTButton>Simpan</BTButton>
 * </BTTooltip>
 *
 * // Rich content
 * <BTTooltip position="bottom" arrowPosition="left" content={<strong>Bold tip</strong>}>
 *   <span>Hover me</span>
 * </BTTooltip>
 * ```
 */
import {
  useState,
  useRef,
  useCallback,
  useEffect,
  type ReactNode,
  type MouseEvent,
  type FocusEvent,
} from 'react';
import { createPortal } from 'react-dom';
import type { BTTooltipPosition, BTTooltipArrowPosition } from './BTTooltip.types';
import './BTTooltip.css';

export interface BTTooltipReactProps {
  /** Plain-text content. Use `content` prop for rich JSX. */
  text?: string;
  /** Rich JSX content — overrides `text`. */
  content?: ReactNode;
  /** Preferred placement relative to trigger. @default 'top' */
  position?: BTTooltipPosition;
  /** Arrow offset along the axis. @default 'mid' */
  arrowPosition?: BTTooltipArrowPosition;
  /** Disable tooltip. @default false */
  disabled?: boolean;
  /** Delay before show (ms). @default 0 */
  showDelay?: number;
  /** Delay before hide (ms). @default 0 */
  hideDelay?: number;
  /** Trigger element (required). */
  children: ReactNode;
  /** Called when the tooltip becomes visible. */
  onShow?: () => void;
  /** Called when the tooltip hides. */
  onHide?: () => void;
}

const GAP = 4;

function getArrowPath(position: BTTooltipPosition): string {
  switch (position) {
    case 'bottom': return 'M0 8 L7 1 Q8 0 9 1 L16 8 Z';
    case 'left':   return 'M0 0 L7 7 Q8 8 7 9 L0 16 Z';
    case 'right':  return 'M8 0 L1 7 Q0 8 1 9 L8 16 Z';
    case 'top':
    default:       return 'M0 0 L7 7 Q8 8 9 7 L16 0 Z';
  }
}

export function BTTooltip({
  text,
  content,
  position = 'top',
  arrowPosition = 'mid',
  disabled = false,
  showDelay = 0,
  hideDelay = 0,
  children,
  onShow,
  onHide,
}: BTTooltipReactProps) {
  const [isVisible, setIsVisible] = useState(false);
  const triggerRef = useRef<HTMLDivElement>(null);
  const balloonRef = useRef<HTMLDivElement>(null);
  const showTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const isHorizontal = position === 'left' || position === 'right';
  const arrowPath = getArrowPath(position);
  const arrowViewBox = isHorizontal ? '0 0 8 16' : '0 0 16 8';
  const arrowW = isHorizontal ? 8 : 16;
  const arrowH = isHorizontal ? 16 : 8;

  const updatePosition = useCallback(() => {
    const trigger = triggerRef.current;
    const balloon = balloonRef.current;
    if (!trigger || !balloon) return;

    const tr = trigger.getBoundingClientRect();
    const bw = balloon.offsetWidth;
    const bh = balloon.offsetHeight;
    const vw = window.innerWidth;
    const vh = window.innerHeight;

    // Trigger centre coords (for arrow alignment)
    const tcx = tr.left + tr.width / 2;
    const tcy = tr.top + tr.height / 2;

    let top = 0;
    let left = 0;

    switch (position) {
      case 'bottom':
        top = tr.bottom + GAP;
        left = tcx - bw / 2;
        break;
      case 'left':
        top = tcy - bh / 2;
        left = tr.left - bw - GAP;
        break;
      case 'right':
        top = tcy - bh / 2;
        left = tr.right + GAP;
        break;
      case 'top':
      default:
        top = tr.top - bh - GAP;
        left = tcx - bw / 2;
        break;
    }

    left = Math.max(8, Math.min(left, vw - bw - 8));
    top = Math.max(8, Math.min(top, vh - bh - 8));

    balloon.style.top = `${top}px`;
    balloon.style.left = `${left}px`;

    // Dynamic arrow offset: px from balloon edge to trigger centre
    const arrowOffset =
      (position === 'left' || position === 'right')
        ? tcy - top
        : tcx - left;
    balloon.style.setProperty('--bt-arrow-offset', `${arrowOffset}px`);
  }, [position]);

  const show = useCallback(() => {
    if (disabled) return;
    if (hideTimerRef.current) { clearTimeout(hideTimerRef.current); hideTimerRef.current = null; }
    showTimerRef.current = setTimeout(() => {
      setIsVisible(true);
      onShow?.();
    }, showDelay);
  }, [disabled, showDelay, onShow]);

  const hide = useCallback(() => {
    if (showTimerRef.current) { clearTimeout(showTimerRef.current); showTimerRef.current = null; }
    hideTimerRef.current = setTimeout(() => {
      setIsVisible(false);
      onHide?.();
    }, hideDelay);
  }, [hideDelay, onHide]);

  // Update position after balloon becomes visible
  useEffect(() => {
    if (isVisible) {
      // Double-rAF to ensure DOM is fully painted with new height
      requestAnimationFrame(() => requestAnimationFrame(updatePosition));
    }
  }, [isVisible, updatePosition]);

  useEffect(() => {
    return () => {
      if (showTimerRef.current) clearTimeout(showTimerRef.current);
      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
    };
  }, []);

  const balloonClass = [
    'bt-tooltip__balloon',
    `bt-tooltip__balloon--${position}`,
    isVisible ? 'bt-tooltip__balloon--visible' : '',
  ].join(' ');

  // Arrow wrappers use no modifier classes — offset set via --bt-arrow-offset in updatePosition
  const arrowRowClass = 'bt-tooltip__arrow-row';
  const arrowColClass = 'bt-tooltip__arrow-col';

  const arrowSvg = (
    <svg
      className="bt-tooltip__arrow"
      width={arrowW}
      height={arrowH}
      viewBox={arrowViewBox}
      fill="none"
      aria-hidden="true"
    >
      <path d={arrowPath} fill="var(--bg-inverse)" />
    </svg>
  );

  return (
    <div
      ref={triggerRef}
      className="bt-tooltip"
      onMouseEnter={show}
      onMouseLeave={hide}
      onFocus={(_e: FocusEvent) => show()}
      onBlur={(_e: FocusEvent) => hide()}
    >
      {children}

      {createPortal(
        <div ref={balloonRef} className={balloonClass} role="tooltip" aria-live="polite">
          {/* Arrow */}
          {!isHorizontal ? (
            <div className={arrowRowClass}>{arrowSvg}</div>
          ) : (
            <div className={arrowColClass}>{arrowSvg}</div>
          )}

          {/* Body */}
          <div className="bt-tooltip__body">
            {content ?? (text ? <p className="bt-tooltip__text">{text}</p> : null)}
          </div>
        </div>,
        document.body,
      )}
    </div>
  );
}

/**
 * BTTooltip — type definitions shared between Vue and React.
 * Figma: https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=479-2624
 */

/** Which side of the trigger the tooltip balloon appears on. */
export type BTTooltipPosition = 'top' | 'bottom' | 'left' | 'right';

/**
 * Where the arrow sits along its axis.
 * - `left` / `right`: ~17 px from the respective edge (Figma L / R positions).
 * - `left-mid` / `right-mid`: 25% / 75% along the axis.
 * - `mid` (default): 50% — centred.
 */
export type BTTooltipArrowPosition =
  | 'left'
  | 'left-mid'
  | 'mid'
  | 'right-mid'
  | 'right';

export interface BTTooltipProps {
  /** Plain-text content shown in the balloon. Use the `content` slot for rich content. */
  text?: string;
  /** Preferred placement relative to the trigger element. @default 'top' */
  position?: BTTooltipPosition;
  /** Arrow offset along the axis. @default 'mid' */
  arrowPosition?: BTTooltipArrowPosition;
  /** Disable the tooltip entirely (no show on hover). @default false */
  disabled?: boolean;
  /** Delay before the balloon appears (ms). @default 0 */
  showDelay?: number;
  /** Delay before the balloon hides (ms). @default 0 */
  hideDelay?: number;
}
